components.codeTemplate:
HStack(alignment: .{alignment}, spacing: {spacing}) {
    Text("Leading")
    Spacer()
    Text("Trailing")
}

VStack(alignment: .{alignment}, spacing: {spacing}) {
    Text("Top")
    Text("Middle")
    Text("Bottom")
}

ZStack(alignment: .{alignment}) {
    Color.accentColor
    Text("On top")
}

ScrollView {
    LazyVStack(alignment: .{alignment}, spacing: {spacing}, pinnedViews: {pinnedViews}) {
        ForEach(items) { item in
            Text(item.title)
        }
    }
}

ScrollView(.horizontal) {
    LazyHStack(alignment: .{alignment}, spacing: {spacing}, pinnedViews: {pinnedViews}) {
        ForEach(items) { item in
            CardView(item)
        }
    }
}

Grid(alignment: .{alignment}, horizontalSpacing: {horizontalSpacing}, verticalSpacing: {verticalSpacing}) {
    GridRow {
        Text("A1")
        Text("B1")
    }
    GridRow {
        Text("A2")
        Text("B2")
    }
}

GridRow(alignment: .{alignment}) {
    Text("Label")
    Image(systemName: "star")
}

ScrollView {
    LazyVGrid(columns: [GridItem(.{columnSizing}, spacing: {gridItemSpacing})], alignment: .{alignment}, spacing: {spacing}, pinnedViews: {pinnedViews}) {
        ForEach(items) { item in
            Color.gray.frame(height: 80)
        }
    }
}

ScrollView(.horizontal) {
    LazyHGrid(rows: [GridItem(.{rowSizing}, spacing: {gridItemSpacing})], alignment: .{alignment}, spacing: {spacing}, pinnedViews: {pinnedViews}) {
        ForEach(items) { item in
            Color.gray.frame(width: 80)
        }
    }
}

ScrollView(.{axes}) {
    LazyVStack {
        ForEach(items) { item in
            RowView(item)
        }
    }
    .scrollTargetLayout()
}
.scrollIndicators(.{scrollIndicators})
.scrollTargetBehavior(.{scrollTargetBehavior})
.scrollBounceBehavior(.{scrollBounceBehavior})
.scrollDisabled({scrollDisabled})
.scrollClipDisabled({scrollClipDisabled})
.scrollPosition($scrollPosition)

ScrollViewReader { proxy in
    ScrollView {
        ForEach(items) { item in
            RowView(item).id(item.id)
        }
    }
    Button("Jump") {
        withAnimation { proxy.scrollTo(targetID, anchor: {targetAnchor}) }
    }
}

List(selection: $selection) {
    ForEach(items) { item in
        Text(item.title)
            .listRowBackground({rowBackground})
            .listRowSeparatorTint({rowSeparatorTint})
            .swipeActions(edge: .trailing) {
                Button(role: .destructive) { delete(item) } label: { Label("Delete", systemImage: "trash") }
            }
    }
    .onMove { from, to in move(from, to) }
    .onDelete { offsets in remove(offsets) }
}
.listStyle(.{style})
.listRowSeparator(.{rowSeparatorVisibility})
.listRowSpacing({rowSpacing})
.listSectionSpacing(.{sectionSpacing})
.environment(\.editMode, $editMode)
.refreshable { await reload() }

Table(people, selection: $selection, sortOrder: $sortOrder) {
    TableColumn("Given Name", value: \.givenName)
    TableColumn("Family Name", value: \.familyName)
    TableColumn("E-Mail", value: \.emailAddress)
}
.tableStyle(.{style})
.tableColumnHeaders(.{columnHeadersVisibility})
.onChange(of: sortOrder) { _, newOrder in people.sort(using: newOrder) }

Form {
    Section("Profile") {
        TextField("Name", text: $name)
        Toggle("Notifications", isOn: $notify)
    }
    Section {
        LabeledContent("Version", value: appVersion)
    }
}
.formStyle(.{style})

Section(isExpanded: $isExpanded) {
    ForEach(items) { Text($0.title) }
} header: {
    Text("{header}")
} footer: {
    Text("{footer}")
}
.headerProminence(.{headerProminence})

GroupBox("{label}") {
    Toggle("Wi-Fi", isOn: $wifi)
    Toggle("Bluetooth", isOn: $bluetooth)
}
.groupBoxStyle(.{style})

DisclosureGroup("{label}", isExpanded: $isExpanded) {
    Toggle("Option A", isOn: $a)
    Toggle("Option B", isOn: $b)
}
.disclosureGroupStyle(.{style})

ViewThatFits(in: .{axes}) {
    HStack { Label("Settings", systemImage: "gear"); Spacer() }
    Image(systemName: "gear")
}

HStack {
    Text("Leading")
    Spacer(minLength: {minLength})
    Text("Trailing")
}

VStack {
    Text("Above")
    Divider()
        .overlay({tint})
    Text("Below")
}

