FlowLayout(spacing: {spacing}) {
    ForEach(tags, id: \.self) { Text($0) }
}

ControlGroup {
    Button { } label: { Label("Add", systemImage: "plus") }
    Button { } label: { Label("Edit", systemImage: "pencil") }
    Button { } label: { Label("Delete", systemImage: "trash") }
} label: {
    Label("{label}", systemImage: "ellipsis")
}
.controlGroupStyle(.{style})

OutlineGroup(rootItems, children: {childrenKeyPath}) { item in
    Label(item.name, systemImage: item.icon)
}

Table(of: Purchase.self) {
    TableColumn("Base price") { Text($0.price, format: .currency(code: "USD")) }
} rows: {
    TableRow(Purchase(price: 20))
    TableRow(Purchase(price: 50))
